import{_ as t,o as n,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"18. Managing Conduct And Performance","description":"","frontmatter":{"title":"18. Managing Conduct And Performance","eba":"Health Allied & Managers Admin 2021-2025","topics":["discipline","union-matters","preliminary"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/consultation-disputes/18-managing-conduct-and-performance.md","filePath":"ebas/has-managers-admin/common-terms/consultation-disputes/18-managing-conduct-and-performance.md"}'),i={name:"ebas/has-managers-admin/common-terms/consultation-disputes/18-managing-conduct-and-performance.md"};function s(a,e,p,c,l,g){return n(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_18-managing-conduct-and-performance" tabindex="-1">18. Managing Conduct And Performance <a class="header-anchor" href="#_18-managing-conduct-and-performance" aria-label="Permalink to &quot;18. Managing Conduct And Performance&quot;">​</a></h1><p><strong>18.1</strong> Application</p><p><strong>(a)</strong> Where an Employer has concerns about:</p><p><strong>(i)</strong> the conduct of an Employee; or</p><p><strong>(ii)</strong> a performance issue that may constitute misconduct, the following procedure will apply.</p><p><strong>(b)</strong> There are two steps in a disciplinary process under this clause as follows:</p><p><strong>(i)</strong> investigative procedure; and</p><p><strong>(ii)</strong> disciplinary procedure.</p><p><strong>(c)</strong> An Employee will be provided a reasonable opportunity to be represented at any time (including by a Union) with respect to all matters set out in this clause.</p><p><strong>(d)</strong> The Employer will notify the Employee in accordance with subclause 18.3(b) as soon as practicable following the Employer becoming aware of the alleged concerns at subclause 18.1(a).</p><p><strong>(e)</strong> Exception – Employees who have not completed a minimum period of employment with their Employer Where an Employee has not completed a period of employment with their Employer of at least the minimum employment period defined at within the Act unless amended) and the Employer is considering the termination of the Employee&#39;s employment, the Employer will:</p><p><strong>(i)</strong> provide the concerns in writing to the Employee as soon as practicable following the Employer becoming aware of the alleged concerns;</p><p><strong>(ii)</strong> advise the Employee of their right to have a representative, including a Union representative;</p><p><strong>(iii)</strong> other than in the case of Serious Misconduct, provide the Employee an opportunity to improve their Performance or Conduct);</p><p><strong>(iv)</strong> meet with the Employee (and, where relevant, their chosen representative); and</p><p><strong>(v)</strong> consider any explanation by the Employee including any matters raised in mitigation before making a decision to terminate the employment. The terms of clause 18.3 to 18.5 inclusive do not apply to Employees within the scope of the exception in this clause 18.1(e).</p><p><strong>18.2</strong> Definitions</p><p><strong>(a)</strong> Performance means the manner in which the Employee fulfils his or her job requirements. The level of performance is determined by an Employee’s knowledge, skills, qualifications, abilities and the requirements of the role.</p><p><strong>(b)</strong> Conduct means the manner in which the Employee behaviour impacts on their work.</p><p><strong>(c)</strong> Misconduct means an Employee’s intentional or negligent failure to abide by or adhere to the standards of conduct expected by the Employer. A performance issue can be considered misconduct where, despite all reasonably practicable interventions by the Employer, the Employee is unable to fulfil all or part of their job requirements to a satisfactory level.</p><p><strong>(d)</strong> Serious misconduct is as defined under the Act and that is both wilful and deliberate. Currently the Act defines serious misconduct, in part, as:</p><p><strong>(i)</strong> wilful or deliberate behaviour by an employee that is inconsistent with the continuation of the contract of employment;</p><p><strong>(ii)</strong> conduct that causes serious and imminent risk to: <strong>(A)</strong> the health or safety of a person; or <strong>(B)</strong> the reputation, viability or profitability of the employer’s business. Conduct that is serious misconduct includes each of the following:</p><p><strong>(iii)</strong> the Employee, in the course of the Employee&#39;s employment, engaging in: <strong>(A)</strong> theft; or</p><p>PART B – CONSULTATION, DISPUTE RESOLUTION AND DISCIPLNE</p><p><strong>(B)</strong> fraud; or <strong>(C)</strong> assault;</p><p><strong>(iv)</strong> the Employee being intoxicated at work;</p><p><strong>(v)</strong> the Employee refusing to carry out a lawful and reasonable instruction that is consistent with the employee&#39;s contract of employment.</p><p><strong>(e)</strong> Subclauses 18.2(d)(iii)-(d)(v) do not apply if the Employee is able to show that, in the circumstances, the conduct engaged in by the Employee was not conduct that made employment in the period of notice unreasonable.</p><p><strong>18.3</strong> Investigative procedure</p><p><strong>(a)</strong> The purpose of an investigative procedure is to conclude whether, on balance, concerns regarding conduct or performance are well- founded and supported by evidence. An investigation procedure must be fair including proper regard to procedural fairness.</p><p><strong>(b)</strong> The Employer will:</p><p><strong>(i)</strong> advise the Employee of the concerns and allegations in writing;</p><p><strong>(ii)</strong> provide the Employee with any material which forms the basis of the concerns before seeking a response;</p><p><strong>(iii)</strong> ensure the Employee is provided a reasonable opportunity to answer any concerns including a reasonable time to respond;</p><p><strong>(iv)</strong> advise the Employee of their right to have a representative, including a Union representative;</p><p><strong>(v)</strong> ensure that the reason for any interview is explained; and</p><p><strong>(vi)</strong> take reasonable steps to investigate the Employee’s response.</p><p><strong>(c)</strong> Where the Employer has complied with subclause 18.3(b)(i)-(b)(iv) and the Employee does not dispute the concerns, the Employee may opt to decline the opportunity to be interviewed.</p><p><strong>(d)</strong> Where the Employee opts to decline the opportunity to be interviewed, the Employee may still raise matters under clause 18.4(c) including matters in mitigation if a disciplinary procedure (see clause 18.4) is proposed.</p><p><strong>18.4</strong> Procedure to address poor Performance or Misconduct</p><p><strong>(a)</strong> The procedure applies if, following the investigation, the Employer reasonably considers that the Employee’s conduct or performance may warrant disciplinary steps being taken.</p><p>PART B – CONSULTATION, DISPUTE RESOLUTION AND DISCIPLNE</p><p><strong>(b)</strong> The Employer will:</p><p><strong>(i)</strong> notify the Employee in writing of the outcome of the investigation process, including the basis of any conclusion; and</p><p><strong>(ii)</strong> provide the Employee with a reasonable opportunity to provide information about the matters in clause 18.4(c).</p><p><strong>(c)</strong> In considering whether to take disciplinary action, the Employer will consider:</p><p><strong>(i)</strong> whether there is a valid reason related to the Conduct or Performance of the Employee arising from the investigation justifying disciplinary action;</p><p><strong>(ii)</strong> whether the Employee knew or ought to have known that the Conduct or Performance was below acceptable standards; and</p><p><strong>(iii)</strong> any explanation by the employee relating to conduct including any matters raised in mitigation.</p><p><strong>18.5</strong> Possible outcomes</p><p><strong>(a)</strong> Where it is determined that having followed the procedures in this clause that disciplinary action is warranted, the Employer may take any of the following steps depending on the seriousness of the Conduct or Performance and the steps shall be recorded on the Employee&#39;s personnel file:</p><p><strong>(i)</strong> where the Performance or Conduct issue does not constitute Serious Misconduct: <strong>(A)</strong> counsel the Employee; <strong>(B)</strong> give the Employee a first written warning; <strong>(C)</strong> give the Employee a second written warning in the event that the Employee has previously been given a first warning within the previous 12 months for that course of Conduct; <strong>(D)</strong> give the Employee a final written warning in the event that the Employee has previously been given a second written warning within the preceding 12 month period for that course of Conduct; <strong>(E)</strong> terminate the Employee’s employment on notice in the case of an employee who repeats a course of Conduct for which a final warning was given in the preceding 12 months; or</p><p><strong>(ii)</strong> for Serious Misconduct:</p><p>PART B – CONSULTATION, DISPUTE RESOLUTION AND DISCIPLNE</p><p><strong>(A)</strong> terminate the Employee’s employment without notice; or <strong>(B)</strong> alternatively, issue the Employee with a final warning without following the steps in subclause 18.5(a)(i) above.</p><p><strong>(b)</strong> The Employer’s decision and a summary of its reasons will be notified to the Employee in writing.</p><p><strong>(c)</strong> If after any warning or counselling, a period of 12 months elapses (as relevant) without the Employee repeating a course of Conduct for which the preceding warning or counselling was given, the Employer cannot rely on the preceding warning or counselling for the purpose of issuing a further warning.</p><p><strong>18.6</strong> Disputes A dispute over the clause (including subclause 18.7) is to be dealt with in accordance with the Dispute Resolution Procedure of this Agreement.</p><p><strong>18.7</strong> Performance Management</p><p><strong>(a)</strong> Nothing in this clause 18 will prevent the Employer from undertaking performance management to support Employees.</p><p><strong>(b)</strong> In this clause 18, performance management includes reasonable actions to address performance by identifying performance deficits, the Employer&#39;s expected outcomes and performance measures, and strategies to meet those measures including the provision of support and education the Employee may reasonably require. Performance management measures may be included in a performance improvement plan that seeks to address the identified deficits within a reasonable time period.</p><p><strong>(c)</strong> In this clause 18, performance management does not include sanctions in addition to those set out at clause 18.5 above.</p><p><strong>18.8</strong> Equal Opportunity when managing conduct and performance of people with disabilities</p><p><strong>(a)</strong> Where an Employee has a Disability, the Employer is required to:</p><p><strong>(i)</strong> make reasonable adjustments to enable the employee to participate in processes to manage conduct and performance in accordance with this Clause 18; and</p><p><strong>(ii)</strong> consider the Employer’s obligations under the Equal Opportunity Act 2010 in making a determination under this clause 18.</p><p><strong>(b)</strong> An Employer is not required to make reasonable adjustments if the Employee could not or cannot adequately participate in the</p><p>PART B – CONSULTATION, DISPUTE RESOLUTION AND DISCIPLNE</p><p>processes to manage conduct and performance in accordance with this Clause 18 even after the adjustments are made.</p><p><strong>(c)</strong> Disability has the same meaning as section 4 of the Equal Opportunity Act 2010.</p><p>PART C – TYPES OF EMPLOYMENT AND TERMINATION OF EMPLOYMENT</p><p>Plain language terms: performance management, disciplinary, misconduct, PIP.</p>',73)])])}const d=t(i,[["render",s]]);export{m as __pageData,d as default};
